{"file_text": "import string
import random
from database import get_db_connection

def generate_short_url(length=6):
    chars = string.ascii_letters + string.digits
    return ''.join(random.choice(chars) for _ in range(length))

class URLModel:
    @staticmethod
    def create_url(original_url):
        conn = get_db_connection()
        short_url = generate_short_url()

        # Ensure uniqueness
        while conn.execute('SELECT id FROM urls WHERE short_url = ?', (short_url,)).fetchone():
            short_url = generate_short_url()

        conn.execute('INSERT INTO urls (original_url, short_url) VALUES (?, ?)',
                     (original_url, short_url))
        conn.commit()
        conn.close()
        return short_url

    @staticmethod
    def get_original_url(short_url):
        conn = get_db_connection()
        url = conn.execute('SELECT original_url FROM urls WHERE short_url = ?',
                           (short_url,)).fetchone()
        conn.close()
        if url:
            return url['original_url']
        return None

    @staticmethod
    def get_all_urls():
        conn = get_db_connection()
        urls = conn.execute('SELECT * FROM urls').fetchall()
        conn.close()
        return urls
